package config

import (
	"encoding/base64"
	"path/filepath"
	"testing"
)

func TestSaveCredentialPersistsBasicAuthPair(t *testing.T) {
	t.Setenv("GLADLY_USERNAME", "")
	t.Setenv("GLADLY_PASSWORD", "")

	cfg, err := Load(filepath.Join(t.TempDir(), "config.toml"))
	if err != nil {
		t.Fatalf("Load returned error: %v", err)
	}
	if err := cfg.SaveCredential("api-key", "secret-key"); err != nil {
		t.Fatalf("SaveCredential returned error: %v", err)
	}

	reloaded, err := Load(cfg.Path)
	if err != nil {
		t.Fatalf("Load persisted config returned error: %v", err)
	}
	want := "Basic " + base64.StdEncoding.EncodeToString([]byte("api-key:secret-key"))
	if got := reloaded.AuthHeader(); got != want {
		t.Fatalf("AuthHeader() = %q, want %q", got, want)
	}
}
